import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;

import org.owasp.encoder.Encode;

public class XssFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitize user input using OWASP Java Encoder library
        String sanitizedInput = Encode.forHtml(userInput);

        // Write sanitized input to output file
        try (BufferedWriter writer = new BufferedWriter(new FileWriter("output.html"))) {
            writer.write("<html><body>");
            writer.write("User input: " + sanitizedInput);
            writer.write("</body></html>");
        }

        System.out.println("Output generated successfully.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
